   1→//! Core sample selection: stratified proportional sampling.
   2→//!
   3→//! Given a set of functions and a call graph, selects a representative subset
   4→//! using stratified proportional sampling across four axes:
   5→//! 1. Module/directory — parent directory of the source file
   6→//! 2. Complexity tier — branch count buckets (0-1, 2-5, 6-15, 16+)
   7→//! 3. Dependency depth — topological layer from the call graph
   8→//! 4. Function kind — pure, I/O, constructor, handler
   9→//!
  10→//! Selection within each stratum uses a stable hash of (file_path, function_name, seed)
  11→//! for deterministic, reproducible results. Dependency closure ensures that if a
  12→//! selected function calls another project function, the callee is also included
  13→//! (without counting against the budget).
  14→
  15→use std::collections::{HashMap, HashSet};
  16→use std::hash::{DefaultHasher, Hash, Hasher};
  17→use std::path::Path;
  18→
  19→use crate::batch_analyze::{FunctionEntry, FunctionRegistry};
  20→use crate::call_graph::CallGraph;
  21→
  22→/// How many functions to sample.
  23→#[derive(Debug, Clone)]
  24→pub enum SampleBudget {
  25→    /// A percentage of total functions (0.0..=100.0).
  26→    Percentage(f64),
  27→    /// An absolute function count.
  28→    Absolute(usize),
  29→}
  30→
  31→/// Configuration for core sample selection.
  32→#[derive(Debug, Clone)]
  33→pub struct CoreSampleConfig {
  34→    /// Budget: how many functions to select.
  35→    pub budget: SampleBudget,
  36→    /// Seed for deterministic selection.
  37→    pub seed: u64,
  38→    /// Root directory of the scan (for computing relative module paths).
  39→    pub scan_root: String,
  40→}
  41→
  42→/// Result of core sample selection.
  43→#[derive(Debug)]
  44→pub struct CoreSampleResult {
  45→    /// Qualified names of functions selected by sampling.
  46→    pub selected: HashSet<String>,
  47→    /// Additional functions included for dependency closure (not counted against budget).
  48→    pub dependency_closure: HashSet<String>,
  49→    /// Per-stratum breakdown for reporting.
  50→    pub strata_summary: Vec<StratumInfo>,
  51→}
  52→
  53→impl CoreSampleResult {
  54→    /// All functions that should be included (selected + closure).
  55→    pub fn all_included(&self) -> HashSet<String> {
  56→        self.selected
  57→            .union(&self.dependency_closure)
  58→            .cloned()
  59→            .collect()
  60→    }
  61→}
  62→
  63→/// Summary of one stratum for reporting.
  64→#[derive(Debug, Clone)]
  65→pub struct StratumInfo {
  66→    /// Human-readable label, e.g. "src/auth | simple(2-5) | depth=1 | pure".
  67→    pub label: String,
  68→    /// Total functions in this stratum.
  69→    pub total: usize,
  70→    /// Functions sampled from this stratum.
  71→    pub sampled: usize,
  72→    /// Names of sampled functions.
  73→    pub names: Vec<String>,
  74→}
  75→
  76→/// Complexity tier based on branch count.
  77→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
  78→enum ComplexityTier {
  79→    Trivial,   // 0-1 branches
  80→    Simple,    // 2-5 branches
  81→    Moderate,  // 6-15 branches
  82→    Complex,   // 16+ branches
  83→}
  84→
  85→impl ComplexityTier {
  86→    fn from_branch_count(count: usize) -> Self {
  87→        match count {
  88→            0..=1 => Self::Trivial,
  89→            2..=5 => Self::Simple,
  90→            6..=15 => Self::Moderate,
  91→            _ => Self::Complex,
  92→        }
  93→    }
  94→
  95→    fn label(self) -> &'static str {
  96→        match self {
  97→            Self::Trivial => "trivial(0-1)",
  98→            Self::Simple => "simple(2-5)",
  99→            Self::Moderate => "moderate(6-15)",
 100→            Self::Complex => "complex(16+)",
 101→        }
 102→    }
 103→}
 104→
 105→/// Function kind classification.
 106→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
 107→enum FunctionKind {
 108→    Pure,
 109→    Io,
 110→    Constructor,
 111→    Handler,
 112→}
 113→
 114→impl FunctionKind {
 115→    fn classify(entry: &FunctionEntry) -> Self {
 116→        let name_lower = entry.name.to_lowercase();
 117→        // Extract just the function name (after last :: if qualified).
 118→        let short_name = name_lower.rsplit("::").next().unwrap_or(&name_lower);
 119→
 120→        // Check for known function name patterns in order of specificity.
 121→        if short_name.contains("handle")
 122→            || short_name.contains("on_")
 123→            || short_name.contains("process")
 124→        {
 125→            return Self::Handler;
 126→        }
 127→        if short_name.starts_with("new")
 128→            || short_name.starts_with("create")
 129→            || short_name.starts_with("init")
 130→            || short_name.starts_with("build")
 131→            || short_name.starts_with("make")
 132→        {
 133→            return Self::Constructor;
 134→        }
 135→        // I/O: has external dependencies or common I/O-related names.
 136→        if !entry.dependencies.is_empty()
 137→            || short_name.contains("read")
 138→            || short_name.contains("write")
 139→            || short_name.contains("fetch")
 140→            || short_name.contains("send")
 141→            || short_name.contains("save")
 142→            || short_name.contains("load")
 143→            || short_name.contains("delete")
 144→        {
 145→            return Self::Io;
 146→        }
 147→        Self::Pure
 148→    }
 149→
 150→    fn label(self) -> &'static str {
 151→        match self {
 152→            Self::Pure => "pure",
 153→            Self::Io => "io",
 154→            Self::Constructor => "constructor",
 155→            Self::Handler => "handler",
 156→        }
 157→    }
 158→}
 159→
 160→/// Composite stratum key.
 161→#[derive(Debug, Clone, PartialEq, Eq, Hash)]
 162→struct StratumKey {
 163→    module: String,
 164→    complexity: ComplexityTier,
 165→    depth: usize,
 166→    kind: FunctionKind,
 167→}
 168→
 169→impl StratumKey {
 170→    fn label(&self) -> String {
 171→        format!(
 172→            "{} | {} | depth={} | {}",
 173→            self.module,
 174→            self.complexity.label(),
 175→            self.depth,
 176→            self.kind.label(),
 177→        )
 178→    }
 179→}
 180→
 181→/// Parse a core-sample argument like "50%", "50", "10%", "200".
 182→pub fn parse_sample_budget(s: &str) -> Result<SampleBudget, String> {
 183→    let s = s.trim();
 184→    if let Some(pct) = s.strip_suffix('%') {
 185→        let val: f64 = pct
 186→            .trim()
 187→            .parse()
 188→            .map_err(|_| format!("invalid percentage: {s}"))?;
 189→        if !(0.0..=100.0).contains(&val) {
 190→            return Err(format!("percentage must be 0-100, got {val}"));
 191→        }
 192→        Ok(SampleBudget::Percentage(val))
 193→    } else {
 194→        let val: usize = s.parse().map_err(|_| format!("invalid count: {s}"))?;
 195→        Ok(SampleBudget::Absolute(val))
 196→    }
 197→}
 198→
 199→/// A batch specifier for progressive batching.
 200→#[derive(Debug, Clone, PartialEq, Eq)]
 201→pub enum BatchSpec {
 202→    /// A single batch index (e.g. `--batch 0`).
 203→    Single(usize),
 204→    /// Auto-detect the next unprocessed batch (e.g. `--batch next`).
 205→    Next,
 206→    /// An inclusive range of batches (e.g. `--batch 0-2`).
 207→    Range(usize, usize),
 208→}
 209→
 210→/// Parse a batch specifier: "0", "next", "0-2".
 211→pub fn parse_batch_spec(s: &str) -> Result<BatchSpec, String> {
 212→    let s = s.trim();
 213→    if s.eq_ignore_ascii_case("next") {
 214→        return Ok(BatchSpec::Next);
 215→    }
 216→    if let Some((left, right)) = s.split_once('-') {
 217→        let start: usize = left
 218→            .trim()
 219→            .parse()
 220→            .map_err(|_| format!("invalid batch range start: {left}"))?;
 221→        let end: usize = right
 222→            .trim()
 223→            .parse()
 224→            .map_err(|_| format!("invalid batch range end: {right}"))?;
 225→        if start > end {
 226→            return Err(format!("batch range start ({start}) > end ({end})"));
 227→        }
 228→        Ok(BatchSpec::Range(start, end))
 229→    } else {
 230→        let idx: usize = s
 231→            .parse()
 232→            .map_err(|_| format!("invalid batch index: {s}"))?;
 233→        Ok(BatchSpec::Single(idx))
 234→    }
 235→}
 236→
 237→/// Select a core sample for a specific batch.
 238→///
 239→/// Batch assignment works by stable-hash sorting all functions within each
 240→/// stratum, then assigning batch numbers via round-robin. This produces
 241→/// disjoint, independently representative batches.
 242→///
 243→/// The `total_batches` parameter controls how many batches the population is
 244→/// divided into (derived from the budget: `total / budget`, minimum 2).
 245→pub fn select_batch(
 246→    entries: &[FunctionEntry],
 247→    call_graph: &CallGraph,
 248→    config: &CoreSampleConfig,
 249→    batch_index: usize,
 250→) -> CoreSampleResult {
 251→    if entries.is_empty() {
 252→        return CoreSampleResult {
 253→            selected: HashSet::new(),
 254→            dependency_closure: HashSet::new(),
 255→            strata_summary: Vec::new(),
 256→        };
 257→    }
 258→
 259→    // Compute budget to determine total_batches.
 260→    let total = entries.len();
 261→    let raw_budget = match config.budget {
 262→        SampleBudget::Percentage(pct) => ((pct / 100.0) * total as f64).round() as usize,
 263→        SampleBudget::Absolute(n) => n,
 264→    };
 265→    let budget = raw_budget.min(total).max(1);
 266→    let total_batches = (total / budget).max(2);
 267→
 268→    // Build qualified names.
 269→    let qualified_names: Vec<String> = entries
 270→        .iter()
 271→        .map(|e| FunctionRegistry::qualified_name(&e.file_path, &e.name))
 272→        .collect();
 273→
 274→    // Assign each function a batch via stable-hash round-robin.
 275→    let mut batch_assignments: Vec<(String, usize)> = Vec::with_capacity(entries.len());
 276→    for (i, entry) in entries.iter().enumerate() {
 277→        let qn = &qualified_names[i];
 278→        let file_path = entry.file_path.to_str().unwrap_or("");
 279→        let hash = stable_hash(file_path, &entry.name, config.seed);
 280→        batch_assignments.push((qn.clone(), hash as usize % total_batches));
 281→    }
 282→
 283→    // Select functions assigned to the target batch.
 284→    let selected: HashSet<String> = batch_assignments
 285→        .iter()
 286→        .filter(|(_, batch)| *batch == batch_index % total_batches)
 287→        .map(|(qn, _)| qn.clone())
 288→        .collect();
 289→
 290→    let dependency_closure = compute_dependency_closure(&selected, call_graph);
 291→
 292→    // Build strata summary for the batch (reuse the existing infrastructure).
 293→    let layers = call_graph.topological_layers();
 294→    let mut depth_map: HashMap<&str, usize> = HashMap::new();
 295→    for (layer_idx, layer) in layers.iter().enumerate() {
 296→        for name in layer {
 297→            depth_map.insert(name.as_str(), layer_idx);
 298→        }
 299→    }
 300→
 301→    let mut strata: HashMap<StratumKey, Vec<&str>> = HashMap::new();
 302→    for (i, entry) in entries.iter().enumerate() {
 303→        let qn = qualified_names[i].as_str();
 304→        if !selected.contains(qn) {
 305→            continue;
 306→        }
 307→        let module = module_from_path(&entry.file_path, &config.scan_root);
 308→        let complexity = ComplexityTier::from_branch_count(entry.branch_count);
 309→        let depth = depth_map.get(qn).copied().unwrap_or(0);
 310→        let kind = FunctionKind::classify(entry);
 311→        let key = StratumKey { module, complexity, depth, kind };
 312→        strata.entry(key).or_default().push(qn);
 313→    }
 314→
 315→    let strata_summary = strata
 316→        .iter()
 317→        .map(|(key, members)| StratumInfo {
 318→            label: key.label(),
 319→            total: members.len(),
 320→            sampled: members.len(),
 321→            names: members.iter().map(|n| n.to_string()).collect(),
 322→        })
 323→        .collect();
 324→
 325→    CoreSampleResult {
 326→        selected,
 327→        dependency_closure,
 328→        strata_summary,
 329→    }
 330→}
 331→
 332→/// Detect the next batch index by checking which batches already have cached behavior maps.
 333→///
 334→/// Returns 0 if no cache is provided or no prior batches are detected.
 335→pub fn detect_next_batch(
 336→    entries: &[FunctionEntry],
 337→    config: &CoreSampleConfig,
 338→    cache: Option<&crate::cache::BehaviorMapCache>,
 339→) -> usize {
 340→    let cache = match cache {
 341→        Some(c) => c,
 342→        None => return 0,
 343→    };
 344→
 345→    let total = entries.len();
 346→    let raw_budget = match config.budget {
 347→        SampleBudget::Percentage(pct) => ((pct / 100.0) * total as f64).round() as usize,
 348→        SampleBudget::Absolute(n) => n,
 349→    };
 350→    let budget = raw_budget.min(total).max(1);
 351→    let total_batches = (total / budget).max(2);
 352→
 353→    let qualified_names: Vec<String> = entries
 354→        .iter()
 355→        .map(|e| FunctionRegistry::qualified_name(&e.file_path, &e.name))
 356→        .collect();
 357→
 358→    // For each batch, check if any function in it has a cached behavior map.
 359→    for batch_idx in 0..total_batches {
 360→        let batch_functions: Vec<&str> = qualified_names
 361→            .iter()
 362→            .enumerate()
 363→            .filter(|(i, _)| {
 364→                let file_path = entries[*i].file_path.to_str().unwrap_or("");
 365→                let hash = stable_hash(file_path, &entries[*i].name, config.seed);
 366→                hash as usize % total_batches == batch_idx
 367→            })
 368→            .map(|(_, qn)| qn.as_str())
 369→            .collect();
 370→
 371→        // If no function in this batch has a cached map, it's the next to run.
 372→        let has_cached = batch_functions
 373→            .iter()
 374→            .any(|qn| cache.load(qn).ok().flatten().is_some());
 375→        if !has_cached {
 376→            return batch_idx;
 377→        }
 378→    }
 379→
 380→    // All batches have some cached data — wrap around.
 381→    0
 382→}
 383→
 384→/// Compute a default seed from a project directory and optional git HEAD.
 385→pub fn default_seed(scan_dir: &str) -> u64 {
 386→    let mut hasher = DefaultHasher::new();
 387→    scan_dir.hash(&mut hasher);
 388→    // Try to incorporate git HEAD for reproducibility across unchanged commits.
 389→    if let Ok(output) = std::process::Command::new("git")
 390→        .args(["rev-parse", "HEAD"])
 391→        .current_dir(scan_dir)
 392→        .output()
 393→        && output.status.success()
 394→    {
 395→        output.stdout.hash(&mut hasher);
 396→    }
 397→    hasher.finish()
 398→}
 399→
 400→/// Select a representative core sample from the given functions.
 401→///
 402→/// The algorithm:
 403→/// 1. Classify each function into a stratum (module x complexity x depth x kind).
 404→/// 2. Allocate the budget proportionally across non-empty strata (min 1 each).
 405→/// 3. Select within each stratum by stable hash ordering.
 406→/// 4. Add transitive callees of selected functions (dependency closure).
 407→pub fn select_core_sample(
 408→    entries: &[FunctionEntry],
 409→    call_graph: &CallGraph,
 410→    config: &CoreSampleConfig,
 411→) -> CoreSampleResult {
 412→    if entries.is_empty() {
 413→        return CoreSampleResult {
 414→            selected: HashSet::new(),
 415→            dependency_closure: HashSet::new(),
 416→            strata_summary: Vec::new(),
 417→        };
 418→    }
 419→
 420→    // Compute the depth layer for each function.
 421→    // topological_layers() returns qualified names (file_path::name).
 422→    let layers = call_graph.topological_layers();
 423→    let mut depth_map: HashMap<&str, usize> = HashMap::new();
 424→    for (layer_idx, layer) in layers.iter().enumerate() {
 425→        for name in layer {
 426→            depth_map.insert(name.as_str(), layer_idx);
 427→        }
 428→    }
 429→
 430→    // Build qualified name for each entry and a lookup map.
 431→    let qualified_names: Vec<String> = entries
 432→        .iter()
 433→        .map(|e| FunctionRegistry::qualified_name(&e.file_path, &e.name))
 434→        .collect();
 435→    let entry_map: HashMap<&str, &FunctionEntry> = entries
 436→        .iter()
 437→        .enumerate()
 438→        .map(|(i, e)| (qualified_names[i].as_str(), e))
 439→        .collect();
 440→
 441→    // Classify each function into a stratum using qualified names.
 442→    let mut strata: HashMap<StratumKey, Vec<&str>> = HashMap::new();
 443→    for (i, entry) in entries.iter().enumerate() {
 444→        let qn = qualified_names[i].as_str();
 445→        let module = module_from_path(&entry.file_path, &config.scan_root);
 446→        let complexity = ComplexityTier::from_branch_count(entry.branch_count);
 447→        let depth = depth_map.get(qn).copied().unwrap_or(0);
 448→        let kind = FunctionKind::classify(entry);
 449→
 450→        let key = StratumKey {
 451→            module,
 452→            complexity,
 453→            depth,
 454→            kind,
 455→        };
 456→        strata.entry(key).or_default().push(qn);
 457→    }
 458→
 459→    // Compute total budget.
 460→    let total = entries.len();
 461→    let raw_budget = match config.budget {
 462→        SampleBudget::Percentage(pct) => ((pct / 100.0) * total as f64).round() as usize,
 463→        SampleBudget::Absolute(n) => n,
 464→    };
 465→    let budget = raw_budget.min(total).max(1);
 466→
 467→    // If budget >= total, select everything.
 468→    if budget >= total {
 469→        let selected: HashSet<String> = qualified_names.iter().cloned().collect();
 470→        let strata_summary = build_strata_summary(&strata, &selected);
 471→        return CoreSampleResult {
 472→            selected,
 473→            dependency_closure: HashSet::new(),
 474→            strata_summary,
 475→        };
 476→    }
 477→
 478→    // Allocate budget proportionally using largest-remainder method.
 479→    let allocations = allocate_budget(&strata, budget);
 480→
 481→    // Select within each stratum by stable hash.
 482→    let mut selected = HashSet::new();
 483→    let mut strata_summary = Vec::new();
 484→
 485→    let mut sorted_keys: Vec<&StratumKey> = allocations.keys().collect();
 486→    sorted_keys.sort_by_key(|k| k.label());
 487→
 488→    for key in sorted_keys {
 489→        let allocation = allocations[key];
 490→        let members = &strata[key];
 491→
 492→        // Sort members by stable hash for deterministic selection.
 493→        let mut scored: Vec<(&str, u64)> = members
 494→            .iter()
 495→            .map(|&name| {
 496→                let file_path = entry_map
 497→                    .get(name)
 498→                    .map_or("", |e| e.file_path.to_str().unwrap_or(""));
 499→                (name, stable_hash(file_path, name, config.seed))
 500→            })
 501→            .collect();
 502→        scored.sort_by_key(|&(_, hash)| hash);
 503→
 504→        let chosen: Vec<String> = scored
 505→            .iter()
 506→            .take(allocation)
 507→            .map(|&(name, _)| name.to_string())
 508→            .collect();
 509→
 510→        for name in &chosen {
 511→            selected.insert(name.clone());
 512→        }
 513→
 514→        strata_summary.push(StratumInfo {
 515→            label: key.label(),
 516→            total: members.len(),
 517→            sampled: chosen.len(),
 518→            names: chosen,
 519→        });
 520→    }
 521→
 522→    // Dependency closure: add transitive callees.
 523→    let dependency_closure = compute_dependency_closure(&selected, call_graph);
 524→
 525→    CoreSampleResult {
 526→        selected,
 527→        dependency_closure,
 528→        strata_summary,
 529→    }
 530→}
 531→
 532→/// Extract a module label from a file path relative to the scan root.
 533→fn module_from_path(file_path: &Path, scan_root: &str) -> String {
 534→    let rel = file_path.strip_prefix(scan_root).unwrap_or(file_path);
 535→    // Use the parent directory as the module label.
 536→    rel.parent()
 537→        .map(|p| {
 538→            let s = p.to_string_lossy().to_string();
 539→            if s.is_empty() {
 540→                ".".to_string()
 541→            } else {
 542→                s
 543→            }
 544→        })
 545→        .unwrap_or_else(|| ".".to_string())
 546→}
 547→
 548→/// Compute a stable hash for deterministic selection within a stratum.
 549→fn stable_hash(file_path: &str, function_name: &str, seed: u64) -> u64 {
 550→    let mut hasher = DefaultHasher::new();
 551→    seed.hash(&mut hasher);
 552→    file_path.hash(&mut hasher);
 553→    function_name.hash(&mut hasher);
 554→    hasher.finish()
 555→}
 556→
 557→/// Allocation entry: (key, floor allocation, fractional remainder).
 558→struct Allocation {
 559→    key: StratumKey,
 560→    count: usize,
 561→    remainder: f64,
 562→}
 563→
 564→/// Allocate budget across strata using the largest-remainder method.
 565→///
 566→/// Each non-empty stratum gets at least 1. The remaining budget is distributed
 567→/// proportionally, with ties broken by fractional remainder.
 568→fn allocate_budget(
 569→    strata: &HashMap<StratumKey, Vec<&str>>,
 570→    budget: usize,
 571→) -> HashMap<StratumKey, usize> {
 572→    let non_empty: Vec<(&StratumKey, usize)> = strata
 573→        .iter()
 574→        .filter(|(_, v)| !v.is_empty())
 575→        .map(|(k, v)| (k, v.len()))
 576→        .collect();
 577→
 578→    let num_strata = non_empty.len();
 579→    if num_strata == 0 {
 580→        return HashMap::new();
 581→    }
 582→
 583→    // If budget can't even give 1 per stratum, give 1 to the largest strata.
 584→    if budget < num_strata {
 585→        let mut by_size: Vec<(&StratumKey, usize)> = non_empty;
 586→        by_size.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.label().cmp(&b.0.label())));
 587→        return by_size
 588→            .into_iter()
 589→            .take(budget)
 590→            .map(|(k, _)| (k.clone(), 1))
 591→            .collect();
 592→    }
 593→
 594→    let total: usize = non_empty.iter().map(|(_, sz)| sz).sum();
 595→
 596→    // Give each stratum floor(proportion * budget), minimum 1.
 597→    // Then distribute remainders.
 598→    let mut allocations: Vec<Allocation> = Vec::new();
 599→    let mut allocated = 0usize;
 600→
 601→    for (key, size) in &non_empty {
 602→        let exact = (*size as f64 / total as f64) * budget as f64;
 603→        let floored = (exact.floor() as usize).max(1).min(*size);
 604→        let remainder = exact - floored as f64;
 605→        allocated += floored;
 606→        allocations.push(Allocation {
 607→            key: (*key).clone(),
 608→            count: floored,
 609→            remainder,
 610→        });
 611→    }
 612→
 613→    // Distribute leftover budget by largest remainder.
 614→    let leftover = budget.saturating_sub(allocated);
 615→    if leftover > 0 {
 616→        allocations.sort_by(|a, b| {
 617→            b.remainder
 618→                .partial_cmp(&a.remainder)
 619→                .unwrap_or(std::cmp::Ordering::Equal)
 620→        });
 621→        for alloc in allocations.iter_mut().take(leftover) {
 622→            let stratum_size = strata[&alloc.key].len();
 623→            if alloc.count < stratum_size {
 624→                alloc.count += 1;
 625→            }
 626→        }
 627→    }
 628→
 629→    allocations
 630→        .into_iter()
 631→        .map(|a| (a.key, a.count))
 632→        .collect()
 633→}
 634→
 635→/// Compute the transitive closure of callees for the selected set.
 636→fn compute_dependency_closure(
 637→    selected: &HashSet<String>,
 638→    call_graph: &CallGraph,
 639→) -> HashSet<String> {
 640→    let mut closure = HashSet::new();
 641→    let mut stack: Vec<String> = selected.iter().cloned().collect();
 642→
 643→    while let Some(func) = stack.pop() {
 644→        for callee in call_graph.callees_of(&func) {
 645→            let callee_str = callee.to_string();
 646→            if !selected.contains(&callee_str) && closure.insert(callee_str.clone()) {
 647→                stack.push(callee_str);
 648→            }
 649→        }
 650→    }
 651→
 652→    closure
 653→}
 654→
 655→/// Build strata summary when all functions are selected (budget >= total).
 656→fn build_strata_summary(
 657→    strata: &HashMap<StratumKey, Vec<&str>>,
 658→    selected: &HashSet<String>,
 659→) -> Vec<StratumInfo> {
 660→    let mut summary: Vec<StratumInfo> = strata
 661→        .iter()
 662→        .map(|(key, members)| {
 663→            let names: Vec<String> = members
 664→                .iter()
 665→                .filter(|n| selected.contains(**n))
 666→                .map(|n| n.to_string())
 667→                .collect();
 668→            StratumInfo {
 669→                label: key.label(),
 670→                total: members.len(),
 671→                sampled: names.len(),
 672→                names,
 673→            }
 674→        })
 675→        .collect();
 676→    summary.sort_by(|a, b| a.label.cmp(&b.label));
 677→    summary
 678→}
