1529→/// Run the scan command: explore multiple functions in dependency order.
1530→#[allow(clippy::too_many_arguments)]
1531→async fn run_scan(
1532→    directory: &str,
1533→    language_filter: Option<&str>,
1534→    include_patterns: &[String],
1535→    exclude_patterns: &[String],
1536→    changed: bool,
1537→    since: Option<&str>,
1538→    include_untracked: bool,
1539→    all_functions: bool,
1540→    max_depth: Option<usize>,
1541→    max_iterations: u32,
1542→    timeout_total: u64,
1543→    cache_dir: Option<&Path>,
1544→    no_cache: bool,
1545→    request_timeout: u64,
1546→    exec_timeout: u64,
1547→    build_timeout: u64,
1548→    parallelism: usize,
1549→    timeout_per_fn: u64,
1550→    timeout_explore: Option<f64>,
1551→    output_dir: Option<&Path>,
1552→    report_format_str: &str,
1553→    progress: bool,
1554→    emit_tests: Option<&str>,
1555→    dry_run: bool,
1556→    resume: Option<&Path>,
1557→    mock_config: Option<&Path>,
1558→    core_sample_spec: Option<&str>,
1559→    core_sample_seed: Option<u64>,
1560→    batch_spec: Option<&str>,
1561→    stratum_spec: Option<&str>,
1562→    log_level: LogLevel,
1563→    memory_limit: Option<u64>,
1564→    project_dir: Option<&Path>,
1565→    use_color: bool,
1566→    seeds_dir: &Path,
1567→    no_seeds: bool,
1568→) -> Result<(), Box<dyn std::error::Error>> {
1569→    let scan_pool_path = if no_seeds {
1570→        None
1571→    } else if seeds_dir.is_absolute() {
1572→        Some(seeds_dir.join("pool.json"))
1573→    } else {
1574→        Some(std::path::PathBuf::from(directory).join(seeds_dir).join("pool.json"))
1575→    };
1576→    let report_format: report::ReportFormat = report_format_str
1577→        .parse()
1578→        .map_err(|e: String| -> Box<dyn std::error::Error> { e.into() })?;
1579→
1580→    // Validate --emit-tests framework early.
1581→    if let Some(framework) = emit_tests
1582→        && framework != "jest" && framework != "vitest" && framework != "gotest"
1583→    {
1584→        return Err(format!(
1585→            "unsupported framework '{framework}': expected 'jest', 'vitest', or 'gotest'"
1586→        )
1587→        .into());
1588→    }
1589→
1590→    // Validate --language if specified.
1591→    if let Some(lang) = language_filter
1592→        && lang != "typescript" && lang != "go" && lang != "rust"
1593→    {
1594→        return Err(format!(
