507→/// Result of a parallel scan across multiple functions.
508→#[derive(Debug)]
509→pub struct ParallelScanResult {
510→    /// Per-function results (only successful explorations).
511→    pub function_results: Vec<FunctionResult>,
512→    /// The order in which functions were tested.
513→    pub test_order: Vec<String>,
514→    /// Functions that were skipped due to timeout or error.
515→    pub skipped: Vec<SkippedFunction>,
516→    /// Number of worker subprocesses used.
