522→/// A channel-based pool of frontend worker subprocesses.
523→///
524→/// Workers are checked out via `recv()` and returned via `send()` after use.
525→/// This ensures exclusive access without lock contention.
526→struct WorkerPool {
527→    sender: tokio::sync::mpsc::Sender<Frontend>,
528→    receiver: Mutex<tokio::sync::mpsc::Receiver<Frontend>>,
529→}
530→
531→impl WorkerPool {
532→    /// Spawn `n` frontend subprocesses and place them in the pool.
533→    async fn spawn(config: &FrontendConfig, n: usize) -> Result<Self, FrontendError> {
534→        let (sender, receiver) = tokio::sync::mpsc::channel(n);
535→        for _ in 0..n {
536→            let frontend = Frontend::spawn(config).await?;
537→            sender.send(frontend).await.expect("channel just created");
538→        }
539→        Ok(Self {
540→            sender,
541→            receiver: Mutex::new(receiver),
542→        })
543→    }
544→
545→    /// Check out a worker from the pool.
546→    async fn checkout(&self) -> Frontend {
547→        let mut rx = self.receiver.lock().await;
548→        rx.recv().await.expect("pool should not be empty")
549→    }
550→
551→    /// Return a worker to the pool.
552→    async fn return_worker(&self, frontend: Frontend) {
553→        let _ = self.sender.send(frontend).await;
554→    }
555→
556→    /// Shut down all workers remaining in the pool.
557→    async fn shutdown(self) {
558→        drop(self.sender);
559→        let mut rx = self.receiver.into_inner();
560→        while let Some(frontend) = rx.recv().await {
561→            let _ = frontend.shutdown().await;
562→        }
563→    }
564→}
